/** The matching of the Trigrams (bagua) and their respective positive (Yang) and negative (Yin) natures
 * with the 5 elements to produce the 10 Celestial Stems
 * Winter Solstice is the Starting point for the Celestial Stems
 */
class CelestialStem {
  constructor(name, symbol, hoMapNumber, trigram, oppositeTrigram, element, alphabeticOrder, polarity) {
    this.name = name;
    this.symbol = symbol;
    this.hoMapNumber = hoMapNumber;
    this.element = element;  
    this.trigram = trigram;
    this.oppositeTrigram = oppositeTrigram;
    this.alphabeticOrder = alphabeticOrder;
    this.polarity = polarity;
  }

  getName() {
    return this.name;
  }

  getSymbol() {
    return this.symbol;
  }
  
  getElement() {
    return this.element;
  }

  getTrigram() {
    return this.trigram;
  }

  getOppositeTrigram() {
    return this.oppositeTrigram;
  }

  getAlphabeticOrder() {
    return this.alphabeticOrder;
  }

  getHoMapNumber() {
    return this.hoMapNumber;
  }

}

class HoraryBranch {
  constructor(name, symbol, hoMapNumbers,element, alphabeticOrder, animal, polarity) {
    this.name = name;
    this.symbol = symbol;
    this.element = element;    
    this.hoMapNumbers = hoMapNumbers;
    this.alphabeticOrder = alphabeticOrder;
    this.animal = animal;
    this.polarity = polarity;
  }

  getName() {
    return this.name;
  }

  getSymbol() {
    return this.symbol;
  }

  getElement() {
    return this.element;
  }
  getHoMapNumbers() {
    return this.hoMapNumbers;
  }

  getAlphabeticOrder() {
    return this.alphabeticOrder;
  }

  getAnimal() {
    return this.animal;
  }
}


